// Use Cheerio to scrape outlets without RSS/API
const cheerio = require('cheerio');
const axios = require('axios');
// Scrape headlines, publish dates, authors from outlet pages
return { scraped_articles: [] };

// Create story_id = SHA256(headline + date)
// Group by story_id, count unique outlets
// Output: deduplicated stories with source_count
const crypto = require('crypto');
const stories = $json.articles;
const seen = {};
const deduped = [];
stories.forEach(article => {
  const hash = crypto.createHash('sha256')
    .update(article.headline + article.date)
    .digest('hex');
  if (!seen[hash]) {
    seen[hash] = { ...article, story_id: hash, sources: [article.outlet_id] };
    deduped.push(seen[hash]);
  } else {
    seen[hash].sources.push(article.outlet_id);
  }
});
return { stories: deduped };

// Parse Twitter results
// Extract: author, followers, engagement
// Look for known AGI voices (Yann, Sam, Demis, etc.)
// Calculate weighted reach
const tweets = $json.tweets;
const amplifiers = tweets.map(tweet => ({
  author: tweet.author_id,
  followers: tweet.public_metrics.followers_count,
  engagement: tweet.public_metrics.like_count + tweet.public_metrics.retweet_count,
  engagement_rate: (tweet.public_metrics.like_count + tweet.public_metrics.retweet_count) / tweet.public_metrics.followers_count,
  weighted_reach: tweet.public_metrics.followers_count * ((tweet.public_metrics.like_count + tweet.public_metrics.retweet_count) / tweet.public_metrics.followers_count)
}));
return { amplifiers };

// Combine amplifiers with accuracy scores
// weighted_credibility = weighted_reach * accuracy_score
// Sort by weighted_credibility
const amplifiers = $json.amplifiers;
const accuracy = $json.accuracy;
const credible = amplifiers.map(amp => ({
  ...amp,
  accuracy_score: accuracy[amp.author] || 0.5,
  weighted_credibility: amp.weighted_reach * (accuracy[amp.author] || 0.5)
})).sort((a,b) => b.weighted_credibility - a.weighted_credibility);
return { top_voices: credible.slice(0, 5) };

// Format for dashboard injection
const story = $json.story;
const voices = $json.top_voices;
return {
  story_id: story.story_id,
  headline: story.headline,
  source_count: story.sources.length,
  sources: story.sources,
  top_voices: voices.map(v => ({ name: v.author, followers: v.followers, accuracy: v.accuracy_score })),
  dashboard_ready: true
};

